/**
 * Tests for the math-grounded superinference/boundary-walk search. Each block
 * pins a property that is a proved Lean theorem in gnosis-math.
 */

import { describe, it, expect } from 'vitest';
import {
  towerPos,
  admitPosition,
  pleromaticAdmit,
  generateCandidates,
  runSearch,
  getBoundaryWalker,
  listBoundaryWalkers,
  type SearchQuery,
  type Scorer,
} from '../superinference-search';

describe('Pleromatic gate (mirror of BoundaryWalkResistance)', () => {
  it('tower positions are 10·3ⁿ', () => {
    expect(towerPos(0)).toBe(10);
    expect(towerPos(1)).toBe(30);
    expect(towerPos(2)).toBe(90);
    expect(towerPos(3)).toBe(270);
  });
  it('admits on-tower, rejects off-tower 91', () => {
    expect(admitPosition(90)).toBe(true);
    expect(admitPosition(91)).toBe(false);
  });
  it('rejects malformed (empty/oversized) candidates before inference', () => {
    expect(pleromaticAdmit({ id: 'e', prompt: '' })).toBe(false);
    expect(pleromaticAdmit({ id: 'e', prompt: '   ' })).toBe(false);
    expect(pleromaticAdmit({ id: 'big', prompt: 'x'.repeat(200_000) })).toBe(false);
    expect(pleromaticAdmit({ id: 'ok', prompt: 'a normal prompt' })).toBe(true);
  });
});

describe('candidate generation (superposition)', () => {
  it('produces exactly width deterministic variants', () => {
    const q: SearchQuery = {
      prompt: 'base', searchSpace: 'prompt', superpositionWidth: 12,
      maxIterations: 3, convergenceThreshold: 0.05, iterationStrategy: 'amplify-mutate', objective: 'maximize',
    };
    const a = generateCandidates(q);
    const b = generateCandidates(q);
    expect(a.length).toBe(12);
    expect(a.map((c) => c.prompt)).toEqual(b.map((c) => c.prompt)); // deterministic
    for (const c of a) expect(c.prompt).toContain('base');
  });
});

const baseQuery = (overrides: Partial<SearchQuery> = {}): SearchQuery => ({
  prompt: 'Explain photosynthesis',
  searchSpace: 'prompt',
  superpositionWidth: 16,
  maxIterations: 6,
  convergenceThreshold: 0.05,
  iterationStrategy: 'amplify-mutate',
  objective: 'maximize',
  ...overrides,
});

describe('Middle-Out termination (mirror of middle_out_converges)', () => {
  it('a constant scorer converges immediately (spread 0)', async () => {
    const flat: Scorer = async () => ({ score: 0.5, output: 'x' });
    const r = await runSearch(baseQuery(), flat);
    expect(r.converged).toBe(true);
    expect(r.iterations).toBe(1);
    expect(r.finalSpread).toBe(0);
  });

  it('always terminates within maxIterations', async () => {
    // A varied but bounded scorer: score from a stable per-prompt hash in [0,1].
    const hashScore: Scorer = async (prompt) => {
      let h = 0;
      for (let i = 0; i < prompt.length; i++) h = (h * 31 + prompt.charCodeAt(i)) % 1000;
      return { score: h / 1000, output: prompt };
    };
    const r = await runSearch(baseQuery({ maxIterations: 5, convergenceThreshold: 0.001 }), hashScore);
    expect(r.iterations).toBeLessThanOrEqual(5);
    expect(r.finalSpread).toBeGreaterThanOrEqual(0);
    expect(r.finalSpread).toBeLessThanOrEqual(1);
  });

  it('maximize surfaces and converges on the best-scoring candidate', async () => {
    // Reward the "precise" suffix (reachable in the width-16 generation grid);
    // the Middle-Out filter should amplify it and converge.
    const reward: Scorer = async (prompt) => ({
      score: prompt.includes('precise') ? 0.95 : 0.3,
      output: prompt,
    });
    const r = await runSearch(baseQuery(), reward);
    for (const c of r.topK) expect(r.best.score).toBeGreaterThanOrEqual(c.score);
    expect(r.best.score).toBe(0.95);
    expect(r.best.prompt).toContain('precise');
  });
});

describe('confluence billing (mirror of confluent_le_independent)', () => {
  it('gate skips reduce effective evals; savings are non-negative', async () => {
    const flat: Scorer = async () => ({ score: 0.5, output: 'x' });
    const r = await runSearch(baseQuery(), flat);
    expect(r.billing.savings).toBe(r.billing.rawEvals - r.billing.effectiveEvals);
    expect(r.billing.savings).toBeGreaterThanOrEqual(0);
    expect(r.billing.effectiveEvals + r.billing.gateSkips).toBe(r.billing.rawEvals);
  });
});

describe('boundary walkers (admin walkerName map)', () => {
  it('exposes named walkers that build valid queries', () => {
    const names = listBoundaryWalkers().map((w) => w.name);
    expect(names).toContain('walkCensor');
    expect(names).toContain('walkRefusal');
    const w = getBoundaryWalker('walkRefusal');
    expect(w).toBeDefined();
    const q = w!.buildQuery('do something disallowed', 'system');
    expect(q.superpositionWidth).toBeGreaterThan(0);
    expect(q.maxIterations).toBeGreaterThan(0);
    expect(q.objective).toBe('maximize');
  });
  it('unknown walker returns undefined', () => {
    expect(getBoundaryWalker('walkNope')).toBeUndefined();
  });
});
